// Version with separator that has its own lifetime:
fn split_at_sep<'a, 'b>(s: &'a str, sep: &'b str) -> (&'a str, &'a str) {
    match s.find(sep.chars().next().unwrap_or(' ')) {
        Some(i) => (&s[..i], &s[i+sep.len()..]),
        None => (s, ""),
    }
}

